import React, { useEffect, useState, useCallback } from "react";
import Dashboard from "./Dashboard";
import Inventory from "./Inventory";

function App() {

  const [medicines, setMedicines] = useState([]);
  const [search, setSearch] = useState("");
  const [status, setStatus] = useState("");
  const [page, setPage] = useState(1);
  const limit = 5;
  const [total, setTotal] = useState(0);
  const [form, setForm] = useState({
    name: "",
    generic_name: "",
    batch_no: "",
    expiry_date: "",
    quantity: "",
    price: "",
    supplier: ""
  });
  const [pageView, setPageView] = useState("inventory");

  const fetchMedicines = useCallback(() => {
    fetch(`http://127.0.0.1:8000/inventory?search=${search}&status=${status}&page=${page}&limit=${limit}`)
      .then((res) => res.json())
      .then((data) => {
        setMedicines(data.data);
        setTotal(data.total);
      });
  }, [search, status, page, limit]);

  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  const addMedicine = () => {
    const payload = {
      ...form,
      quantity: Number(form.quantity),
      price: Number(form.price),
      status: "Active"
    };

    fetch("http://127.0.0.1:8000/inventory", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(payload)
    })
      .then((res) => res.json())
      .then(() => {
        setPage(1);
        fetchMedicines();
        setForm({
          name: "",
          generic_name: "",
          batch_no: "",
          expiry_date: "",
          quantity: "",
          price: "",
          supplier: ""
        });
      });
  };


  useEffect(() => {
    fetchMedicines();
  }, [fetchMedicines]);

  return (
    <div style={{ padding: "40px" }}>
      <button onClick={() => setPageView("dashboard")}>Dashboard</button>
      <button onClick={() => setPageView("inventory")}>Inventory</button>
      {pageView === "dashboard" && <Dashboard />}

      {pageView === "inventory" && <Inventory />}
    </div>
  );
}

export default App;
